#include <windows.h>
#include <stdio.h>

// Function to capture screen and save it as BMP file
void CaptureScreen() {
    HWND hDesktop = GetDesktopWindow();
    HDC hDesktopDC = GetDC(hDesktop);
    HDC hMemDC = CreateCompatibleDC(hDesktopDC);

    int width = GetSystemMetrics(SM_CXSCREEN);
    int height = GetSystemMetrics(SM_CYSCREEN);

    HBITMAP hBitmap = CreateCompatibleBitmap(hDesktopDC, width, height);
    SelectObject(hMemDC, hBitmap);

    BitBlt(hMemDC, 0, 0, width, height, hDesktopDC, 0, 0, SRCCOPY);

    char buffer[256];
    GetModuleFileName(NULL, buffer, sizeof(buffer));
    char* dir_end = strrchr(buffer, '\\');
    if (dir_end) *++dir_end = '\0';

    // Save bitmap as BMP file
    BITMAPFILEHEADER bmfHeader;
    BITMAPINFOHEADER bi;

    ZeroMemory(&bi, sizeof(bi));
    bi.biSize = sizeof(BITMAPINFOHEADER);
    bi.biWidth = width;
    bi.biHeight = -height; // negative for top-down DIB
    bi.biPlanes = 1;
    bi.biBitCount = 32;
    bi.biCompression = BI_RGB;

    DWORD dwBmpSize =width*height*4;

    ZeroMemory(&bmfHeader, sizeof(bmfHeader));
    bmfHeader.bfType = 0x4D42; // 'BM'
    bmfHeader.bfSize = sizeof(BITMAPFILEHEADER) + sizeof(BITMAPINFOHEADER) + dwBmpSize;
    bmfHeader.bfOffBits = sizeof(BITMAPFILEHEADER) + sizeof(BITMAPINFOHEADER);

    FILE* f = fopen(strcat(strcat(buffer, "screenshot.bmp"), ""), "wb");
    fwrite(&bmfHeader, 1, sizeof(bmfHeader), f);
    fwrite(&bi, 1, sizeof(bi), f);
    BYTE* pBits = NULL;
    GetDIBits(hMemDC, hBitmap, 0, height, NULL, (BITMAPINFO*)&bi, DIB_RGB_COLORS);
    GetDIBits(hMemDC, hBitmap, 0, height, pBits, (BITMAPINFO*)&bi, DIB_RGB_COLORS);
    fwrite(pBits, 1, dwBmpSize, f);

    fclose(f);

