 * Screenshot Grabber in C Using GDI
 *
 * This program is a simple demonstration of how to capture a screenshot
 * of the entire screen using the Windows Graphics Device Interface (GDI).
 *
 * Usage: Compile this source file and run the executable.
 *        A window will appear with the captured screenshot.
 */

#include <windows.h>
#include <gdiplus.h>

#pragma comment(lib, "gdi32.lib")
#pragma comment(lib, "user32.lib")
#pragma comment(lib, "gdiplus.lib")

#define SCREENSHOT_FILE "screenshot.bmp"

void CaptureScreen() {
    HBITMAP hBitmap;
    HDC hdcScreen = GetDC(NULL);
    HDC hdcMem = CreateCompatibleDC(hdcScreen);
    RECT rect;

    // Get screen dimensions
    GetWindowRect(GetDesktopWindow(), &rect);
    int width = rect.right - rect.left;
    int height = rect.bottom - rect.top;

    // Create bitmap
    hBitmap = CreateCompatibleBitmap(hdcScreen, width, height);
    SelectObject(hdcMem, hBitmap);

    // BitBlt to capture screen
    BitBlt(hdcMem, 0, 0, width, height, hdcScreen, 0, 0, SRCCOPY);

    BITMAPFILEHEADER bmpFileHeader;
    BITMAPINFOHEADER bmpInfoHeader;
    BYTE* pBits;
    DWORD dwSize;

    // Prepare BMP headers
    GetObject(hBitmap, sizeof(BITMAP), &bmpInfoHeader);
    dwSize = width * height * 3;
    pBits = GlobalAlloc(GMEM_MOVEABLE, dwSize);
    GetDIBits(hdcMem, hBitmap, 0, height, pBits, (BITMAPINFO*)&bmpInfoHeader, DIB_RGB_COLORS);

    bmpFileHeader.bfType = 0x4D42; // 'BM'
    bmpFileHeader.bfSize = sizeof(bmpFileHeader) + sizeof(bmpInfoHeader) + dwSize;
    bmpFileHeader.bfReserved1 = 0;
    bmpFileHeader.bfReserved2 = 0;
    bmpFileHeader.bfOffBits = sizeof(bmpFileHeader) + sizeof(bmpInfoHeader);

    // Save to BMP file
    FILE* f = fopen(SCREENSHOT_FILE, "wb");
    if (f) {
        fwrite(&bmpFileHeader, 1, sizeof(bmpFileHeader), f);
        fwrite(&bmpInfoHeader, 1, sizeof(bmpInfoHeader), f);
        fwrite(pBits, 1, dwSize, f);
        fclose(f);
    }

    // Clean up
    GlobalFree(pBits);
    DeleteDC(hdcMem);
    ReleaseDC(NULL, hdcScreen);
    DeleteObject(hBitmap);
}

int main() {
    // Initialize GDI+
    ULONG_PTR gdiplusToken;
    GdiplusStartupInput gdiplusStartupInput = {0};
    GdiplusStartup(&gdiplusToken, &gdiplusStartupInput, NULL);

    CaptureScreen();

    // Shutdown GDI+
    GdiplusShutdown(gdiplusToken);

    MessageBox(NULL, "Screenshot saved as screenshot.bmp", "Success", MB_OK);
    return 0;
}

